const ARTWORKS = [
  { id: 1, title: "ArtWork1", file: "/ArtWork1.jpeg" },
  { id: 2, title: "ArtWork2", file: "/ArtWork2.jpeg" },
  { id: 3, title: "ArtWork3", file: "/ArtWork3.jpeg" },
  { id: 4, title: "ArtWork4", file: "/ArtWork4.jpeg" },
  { id: 5, title: "ArtWork5", file: "/Artwork5.jpeg" },
  { id: 6, title: "ArtWork6", file: "/ArtWork6.jpeg" },
  { id: 7, title: "ArtWork 7", file: "/ArtWork7.jpeg" },
  { id: 8, title: "ArtWork 8", file: "/ArtWork8.jpeg" },
];

export default function Gallery() {
  return (
    <section id="gallery" className="py-24 px-6 md:px-12 border-t border-yellow-500/10">
      <div className="max-w-6xl mx-auto">

        {/* Header */}
        <div className="text-center mb-16">
          <p className="text-xs font-bold tracking-widest uppercase text-yellow-600 mb-3">Works</p>
          <h2 className="font-serif font-black mb-4" style={{ fontSize: "clamp(2rem, 5vw, 3.5rem)", letterSpacing: "-0.03em" }}>
            Featured <span className="gold-text">Gallery</span>
          </h2>
          <div className="brush-line w-24 mx-auto mb-6" />
          <p className="text-yellow-100/40 max-w-xl mx-auto text-sm leading-relaxed">
            A curated glimpse into Subham's body of work — each piece a window into a different dimension of artistic expression.
          </p>
        </div>

        {/* Gallery Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
          {ARTWORKS.map((art) => (
            <div key={art.id} className="art-card group overflow-hidden cursor-pointer">

              {/* Image */}
              <div className="relative h-64 overflow-hidden">
                <img
                  src={art.file}
                  alt={art.title}
                  className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                />

                {/* Hover overlay */}
                <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-all duration-300 flex flex-col items-center justify-center"
                  style={{ background: "rgba(10,0,8,0.75)", backdropFilter: "blur(4px)" }}>
                  <div className="text-yellow-400 text-2xl mb-2">✦</div>
                  <div className="text-yellow-300 font-serif font-bold text-sm">{art.title}</div>
                  <div className="text-yellow-500/60 text-xs mt-1">by Subham Das</div>
                </div>

                {/* Number badge */}
                <div className="absolute top-3 left-3 w-7 h-7 rounded-full gold-bg flex items-center justify-center text-black text-xs font-black shadow-lg">
                  {art.id}
                </div>
              </div>

              {/* Bottom info */}
              <div className="p-4 flex items-center justify-between">
                <span className="font-serif font-bold text-sm gold-text">{art.title}</span>
                <span className="text-yellow-500/40 text-xs">Subham Das</span>
              </div>

            </div>
          ))}
        </div>

      </div>
    </section>
  );
}
